def check_key(key: bytes) -> bool:
    if len(key) != 8:
        return False
    acc = 0
    for i, b in enumerate(key):
        acc += ((b ^ 0x5A) + i)
        acc &= 0xffffffff
    return acc == 0x2F4

print(check_key(b'AAAAAAAB'))
